import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Button, icon } from 'decantr/components';

code.example:
function ChatInput({ onSend, onAttach }) {
  const { div, textarea, input } = tags;
  const [value, setValue] = createSignal('');
  const [files, setFiles] = createSignal([]);

  const handleKeyDown = (e) => {
    if (e.key === 'Enter' && (e.metaKey || e.ctrlKey)) {
      e.preventDefault();
      handleSend();
    }
  };

  const handleSend = () => {
    if (!value().trim() && files().length === 0) return;
    onSend({ content: value(), attachments: files() });
    setValue('');
    setFiles([]);
  };

  return div({ class: css('_flex _col _gap2 _p4 _borderT _bgbg') },
    files().length > 0 ? div({ class: css('_flex _gap2 _flexWrap') },
      ...files().map((f, i) =>
        div({ class: css('_flex _aic _gap1 _px2 _py1 _r1 _bgmuted/10') },
          icon('file', { size: '14' }),
          span({}, f.name),
          Button({ variant: 'ghost', size: 'xs', onclick: () => setFiles(files().filter((_, j) => j !== i)) },
            icon('x', { size: '12' })
          )
        )
      )
    ) : null,
    div({ class: css('_flex _gap2 _aic') },
      input({ type: 'file', multiple: true, class: css('_hidden'), id: 'file-input',
        onchange: (e) => setFiles([...files(), ...e.target.files]) }),
      Button({ variant: 'ghost', onclick: () => document.getElementById('file-input').click() },
        icon('paperclip')
      ),
      textarea({
        class: css('carbon-input _flex1 _resize[none] _minh[40px] _maxh[200px] _p2 _r2'),
        placeholder: 'Type a message...',
        value: value(),
        oninput: (e) => setValue(e.target.value),
        onkeydown: handleKeyDown,
        rows: 1
      }),
      Button({ variant: 'primary', onclick: handleSend, disabled: !value().trim() && files().length === 0 },
        icon('send'), 'Send'
      )
    )
  );
}

