function RichChatInput({ onSend, onAttach, maxTokens = 4000 }) {
  const { div, textarea, span } = tags;
  const [value, setValue] = createSignal('');
  const [showMentions, setShowMentions] = createSignal(false);

  const tokenCount = () => Math.ceil(value().length / 4);

  return div({ class: css('_flex _col _gap2 _p4 _borderT _bgbg carbon-card _r2 _m4') },
    div({ class: css('_flex _gap1 _pb2 _borderB') },
      Button({ variant: 'ghost', size: 'xs' }, icon('bold', { size: '14' })),
      Button({ variant: 'ghost', size: 'xs' }, icon('italic', { size: '14' })),
      Button({ variant: 'ghost', size: 'xs' }, icon('code', { size: '14' })),
      Button({ variant: 'ghost', size: 'xs' }, icon('link', { size: '14' }))
    ),
    textarea({
      class: css('carbon-input _wfull _resize[none] _minh[80px] _maxh[300px] _p2 _r2 _border0'),
      placeholder: 'Type a message... Use @mention, Cmd+Enter to send',
      value: value(),
      oninput: (e) => setValue(e.target.value)
    }),
    div({ class: css('_flex _jcsb _aic') },
      div({ class: css('_flex _gap2') },
        Button({ variant: 'ghost', size: 'sm' }, icon('paperclip')),
        Button({ variant: 'ghost', size: 'sm' }, icon('smile'))
      ),
      div({ class: css('_flex _aic _gap3') },
        span({ class: css('_textsm _fgmuted') }, `${tokenCount()} / ${maxTokens} tokens`),
        Button({ variant: 'primary', size: 'sm' }, icon('send'), 'Send')
      )
    )
  );
}

